const raw = $input.first().json.message?.content || $input.first().json.content || "";

// Turn escaped newlines into real ones and strip markdown
const text = raw
  .replace(/\\n/g, "\n")
  .replace(/\*\*/g, "")
  .trim();

function extract(patterns, source) {
  for (const pattern of patterns) {
    const match = source.match(pattern);
    if (match && match[1]) {
      return match[1].trim();
    }
  }
  return "Unknown";
}

const fullName = extract([
  /Full Name:\s*(.+)/i,
  /Client(?:'s)? Full Name:\s*(.+)/i
], text);

const packageName = extract([
  /Package\/Membership:\s*(.+)/i,
  /Package or Membership:\s*(.+)/i,
  /Package:\s*(.+)/i
], text);

const recentVisit = extract([
  /most recent visit date is\s*([0-9]{4}-[0-9]{2}-[0-9]{2})/i,
  /Most Recent Visit Date:\s*([0-9]{4}-[0-9]{2}-[0-9]{2})/i,
  /last appointment was on\s*([0-9]{4}-[0-9]{2}-[0-9]{2})/i
], text);

let summary = extract([
  /Based on the available information, here is a brief summary of this client:\s*([\s\S]*?)(?:If there are no more appointments available|$)/i,
  /Brief Summary for Next Consultant\s*([\s\S]*?)(?:If there are no more appointments available|$)/i
], text);

summary = summary
  .replace(/^[:\-\s]+/, "")
  .trim();

const bookingLineMatch = text.match(/(If there are no more appointments available,.*)/i);
const bookingLine = bookingLineMatch ? bookingLineMatch[1].trim() : "Unknown";

const formattedOutput = `Based on the provided JSON data, here are the extracted information and client summary:


Client Details


Full Name: ${fullName}

Package/Membership: ${packageName}


Most Recent Visit Date


The most recent visit date is ${recentVisit}.


Brief Summary for Next Consultant


Based on the available information, here is a brief summary of this client:


${summary}


${bookingLine}`;

return [
  {
    json: {
      formattedOutput
    }
  }
];
